const athleteData = $('Read Athlete Profile').first().json;
const athlete = athleteData.fields ?? athleteData;

const rawDate = athlete.hyrox_target_date || '2026-07-18';
const targetDate = new Date(rawDate);
const now = new Date();
const daysToRace = Math.floor((targetDate - now) / (1000 * 60 * 60 * 24));
const weeksToRace = Math.ceil(daysToRace / 7);

let phase;
if (weeksToRace <= 2) phase = 'Taper';
else if (weeksToRace <= 5) phase = 'Peak';
else if (weeksToRace <= 12) phase = 'Build';
else phase = 'Base';

const totalPrepWeeks = 20;
const weekNumber = Math.max(1, totalPrepWeeks - weeksToRace + 1);

const today = new Date();
const dayOfWeek = today.getDay();
const daysUntilMonday = dayOfWeek === 0 ? 1 : (8 - dayOfWeek);
const nextMonday = new Date(today);
nextMonday.setDate(today.getDate() + daysUntilMonday);
const nextSunday = new Date(nextMonday);
nextSunday.setDate(nextMonday.getDate() + 6);

const isoDate = d => d.toISOString().slice(0, 10);

return [{
  json: {
    phase,
    weeks_to_race: weeksToRace,
    week_number: weekNumber,
    week_start: isoDate(nextMonday),
    week_end: isoDate(nextSunday),
    week_dates: Array.from({length: 7}, (_, i) => {
      const d = new Date(nextMonday);
      d.setDate(nextMonday.getDate() + i);
      return isoDate(d);
    })
  }
}];

const rawItems = $input.all();
const calendarItems = rawItems.filter(item => item.json && item.json.summary);

const computePhase = $('Compute Phase').first().json;

const calendarContext = calendarItems.length === 0
  ? 'No calendar events next week.'
  : calendarItems.map(item => {
    const event = item.json;
    const startDate = (event.start && event.start.dateTime)
      ? event.start.dateTime.substring(0, 10)
      : ((event.start && event.start.date) ? event.start.date : '?');
    const summary = event.summary || 'Untitled event';
    const location = event.location ? ' [Location: ' + event.location + ']' : '';
    return startDate + ': ' + summary + location;
  }).join('\n');

return [{
  json: {
    phase: computePhase.phase,
    weeks_to_race: computePhase.weeks_to_race,
    week_number: computePhase.week_number,
    week_start: computePhase.week_start,
    week_end: computePhase.week_end,
    week_dates: computePhase.week_dates,
    calendar_context: calendarContext
  }
}];

