const output = $('Plan Week AI Agent').first().json.output;
const phase = $('Compute Phase').first().json;

// ── Message 1: Training sessions ─────────────────────────────────────────────
const sessionLines = output.sessions.map(s => {
  const travelTag = (s.notes && s.notes.indexOf('Travel day') === 0) ? ' (\u2708\ufe0f travel)' : '';
  return '*' + s.date + travelTag + '* \u2014 ' + s.session_type + ' (' + s.duration_min + 'min, ' + s.intensity + ')\n' + s.description;
}).join('\n\n');

const msg1 = '\ud83d\udcc5 *Weekly Plan \u2014 Week of ' + phase.week_start + '*\n' +
  'Phase: ' + phase.phase + ' \u2014 Week ' + phase.week_number + ' (' + phase.weeks_to_race + ' weeks to race)\n\n' +
  sessionLines;

// ── Message 2: Nutrition + grocery list ──────────────────────────────────────
const nutritionLines = output.nutrition.daily_plans.map(d => {
  const groceries = (d.daily_groceries && d.daily_groceries.length > 0)
    ? '\n\ud83d\uded2 ' + d.daily_groceries.join(' \u00b7 ')
    : '';
  return '*' + d.date + '* \u2014 ' + d.calories + ' kcal | ' + d.protein_g + 'g P / ' + d.carbs_g + 'g C / ' + d.fat_g + 'g F\n' + d.meals + groceries;
}).join('\n\n');

const msg2 = '\ud83e\udd57 *Nutrition \u2014 day by day*\n\n' + nutritionLines;

// ── Message 3: Batch cooking ──────────────────────────────────────────────────
const dishLines = output.batch_cooking.dishes.map(d =>
  '*' + d.name + '* (' + d.servings + ' servings \u2014 ' +
  d.macros_per_serving.calories + ' kcal | ' + d.macros_per_serving.protein_g + 'g P / ' +
  d.macros_per_serving.carbs_g + 'g C / ' + d.macros_per_serving.fat_g + 'g F per serving)\n' +
  d.instructions
).join('\n\n');

const batchGrocery = output.batch_cooking.grocery_list.map(i => '\u2022 ' + i).join('\n');

const msg3 = '\ud83c\udf73 *Batch cooking option* (lazy Sunday prep)\n' +
  output.batch_cooking.intro + '\n\n' + dishLines +
  '\n\n\ud83d\uded2 *Batch cooking groceries*\n' + batchGrocery +
  '\n\nTraining plan saved to Airtable.';

return [
  { json: { telegram_text: msg1 } },
  { json: { telegram_text: msg2 } },
  { json: { telegram_text: msg3 } }
];
